INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (4, '价格', '购物车价格', '新品跟卖老品，通过设置更低的新品价格来获取购物车，提升转化', 40, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (4, '价格', '高/低客单价区间对价格的敏感度', '客单价高/低的产品价格敏感度区间不一样，因此不同幅度的价格调整对转化的提升也是不一样的。考虑产品客单价的高低，把握价格敏感度来提升转化', 41, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (5, '限购', '限购', '商品限购也会造成饥饿感', 42, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (5, '限购', '限购', '商品限购会影响买家多套下单，尤其是企业买家的大批量购买需求', 43, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (5, '限购', '限购', '对于不同产品、不同库存灵活运用是否限购提升转化', 44, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (6, '配送', '配送方式', 'FBA优于FBM', 45, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (6, '配送', '配送时效', 'FBM发货配送时效缩短，设置处理时间和头程发货仓库库存分布。', 46, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (6, '配送', '不低于$25的商品', '避免让客户承担配送费/亚马逊多次收尾程费', 47, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (7, '变体', '变体数量', '符合亚马逊规则要求，不宜过多，造成选择障碍', 48, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (7, '变体', '变体名称', '清晰易懂，不产生理解误差，减少决策阻碍', 49, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (7, '变体', '变体图片', '分类直观展现，方便理解变体间差异，减少决策阻碍（多种产品属性叠加命名，有可能利于提升转化，但属于违规行为不建议使用）', 50, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (7, '变体', '变体逻辑', '父体结构合理，变体结构有逻辑并符合消费者习惯', 51, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (7, '变体', '变体价格', '保证PC端和手机端均能清晰表达', 52, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (8, '产品信息', '完整性', '更多的产品详细信息，既利于客户检索产品参数与自己需求是否匹配，也能体现卖家专业性，不出现误导顾客的信息', 53, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (8, '产品信息', '正确性', '产品描述与实际一致，减少售后问题和产品审核风险', 54, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (8, '产品信息', '合规性', '不出现亚马逊违规信息', 55, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (9, '商品文档', '产品介绍/安装文档', '添加产品使用说明等文案以解决顾客问题，关心安装的用户可以快速看到安装手册', 56, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (9, '商品文档', '检测报告/安全认证', '满足平台合规，提升专业度和客户信任度', 57, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (10, '主图', '首图', '图片像素、清晰度、留白比例', 58, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (10, '主图', '首图', '主图场景化，让消费者有获得感和满足感，知道使用效果，体现产品差异化', 59, NULL, 0);

